import type { AttachmentData } from '../attachments/attachment.types';

export type PromptInputState =
  | 'ready'
  | 'submitted'
  | 'streaming'
  | 'error';

export type PromptInputSize = 'sm' | 'md' | 'lg';

export type PromptInputVariant = 'default' | 'ghost' | 'bordered';

export interface PromptInputSubmitEvent {
  value: string;
  attachments: readonly AttachmentData[];
  preventDefault: () => void;
}

export interface PromptInputAttachmentError {
  file: File;
  reason: 'invalid-mime' | 'too-large' | 'max-count';
  message: string;
}

export interface PromptInputModelOption {
  id: string;
  label: string;
  description?: string;
  badge?: string;
  disabled?: boolean;
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  ElementRef,
  HostListener,
  inject,
  input,
  model,
  output,
  signal,
  ViewEncapsulation,
} from '@angular/core';
import { cva } from 'class-variance-authority';
import { cn } from '@gremorie/ng-core';
import { toAttachmentData } from '../attachments/attachment.utils';
import type { AttachmentData } from '../attachments/attachment.types';

import {
  PromptInputAttachmentError,
  PromptInputSize,
  PromptInputState,
  PromptInputSubmitEvent,
  PromptInputVariant,
} from './prompt-input.types';

const containerVariants = cva(
  'relative flex w-full flex-col rounded-md transition-colors focus-within:ring-2 focus-within:ring-ring focus-within:ring-offset-2 focus-within:ring-offset-background',
  {
    variants: {
      size: {
        sm: 'gap-1.5 p-2.5 text-sm',
        md: 'gap-2 p-3 text-sm',
        lg: 'gap-3 p-4 text-base',
      },
      variant: {
        default: 'border border-input bg-background',
        ghost: 'border border-transparent bg-transparent',
        bordered: 'border-2 border-input bg-background',
      },
      state: {
        ready: '',
        submitted: '',
        streaming: '',
        error: 'border-destructive focus-within:ring-destructive',
      },
    },
    defaultVariants: {
      size: 'md',
      variant: 'default',
      state: 'ready',
    },
  },
);

@Component({
  selector: 'prompt-input',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <ng-content />
    <span class="sr-only" aria-live="polite" aria-atomic="true">{{ statusAnnouncement() }}</span>
  `,
  host: {
    role: 'form',
    '[class]': 'hostClass()',
    '[attr.aria-label]': 'ariaLabel()',
    '[attr.aria-disabled]': 'disabled() ? "true" : null',
    '[attr.data-state]': 'state()',
    '[attr.data-disabled]': 'disabled() ? "" : null',
    '[attr.data-dragging]': 'isDragging() ? "" : null',
    '(keydown)': 'handleKeydown($event)',
    '(dragover)': 'handleDragOver($event)',
    '(dragenter)': 'handleDragEnter($event)',
    '(dragleave)': 'handleDragLeave($event)',
    '(drop)': 'handleDrop($event)',
  },
})
export class PromptInput {
  private readonly elementRef: ElementRef<HTMLElement> = inject(ElementRef);

  readonly value = model<string>('');
  readonly attachments = model<readonly AttachmentData[]>([]);

  readonly state = input<PromptInputState>('ready');
  readonly size = input<PromptInputSize>('md');
  readonly variant = input<PromptInputVariant>('default');
  readonly disabled = input<boolean>(false);
  readonly submitOnEnter = input<boolean>(true);
  readonly ariaLabel = input<string>('AI prompt input');

  /**
   * When `false`, file attachments are disabled (drag-drop and paste ignored).
   * Otherwise, an array of MIME patterns (`image/*`, `application/pdf`, etc.)
   * that are accepted.
   */
  readonly acceptAttachments = input<readonly string[] | false>(false);
  readonly maxAttachments = input<number>(10);
  readonly maxAttachmentSize = input<number>(10 * 1024 * 1024); // 10MB

  readonly submitted = output<PromptInputSubmitEvent>();
  readonly canceled = output<void>();
  readonly retried = output<void>();
  readonly attachmentError = output<PromptInputAttachmentError>();

  private readonly dragCounter = signal(0);

  readonly isDragging = computed(() => this.dragCounter() > 0);

  readonly attachmentsEnabled = computed(() => {
    const accept = this.acceptAttachments();
    return accept !== false && !this.disabled();
  });

  readonly statusAnnouncement = computed(() => {
    switch (this.state()) {
      case 'submitted':
        return 'Message submitted. Waiting for response.';
      case 'streaming':
        return 'AI is responding.';
      case 'error':
        return 'Submission failed. Press the button to retry.';
      default:
        return '';
    }
  });

  readonly hostClass = computed(() =>
    cn(
      containerVariants({
        size: this.size(),
        variant: this.variant(),
        state: this.state(),
      }),
      this.disabled() && 'pointer-events-none opacity-50',
      this.isDragging() && 'ring-2 ring-ring ring-offset-2',
    ),
  );

  handleKeydown(event: KeyboardEvent): void {
    if (this.disabled()) {
      return;
    }

    const isEnter = event.key === 'Enter';
    const isMod = event.metaKey || event.ctrlKey;

    if (isEnter && isMod) {
      event.preventDefault();
      this.submit();
      return;
    }

    if (isEnter && !event.shiftKey && this.submitOnEnter()) {
      event.preventDefault();
      this.submit();
      return;
    }

    if (event.key === 'Escape') {
      event.preventDefault();
      this.handleEscape();
    }
  }

  @HostListener('document:keydown', ['$event'])
  handleGlobalKeydown(event: KeyboardEvent): void {
    const isMod = event.metaKey || event.ctrlKey;
    if (isMod && event.key.toLowerCase() === 'k') {
      event.preventDefault();
      this.focusTextarea();
    }
  }

  @HostListener('paste', ['$event'])
  handlePaste(event: ClipboardEvent): void {
    if (!this.attachmentsEnabled()) {
      return;
    }
    const items = event.clipboardData?.items;
    if (!items) {
      return;
    }
    const files: File[] = [];
    for (let i = 0; i < items.length; i++) {
      const item = items[i];
      if (item.kind === 'file') {
        const file = item.getAsFile();
        if (file) {
          files.push(file);
        }
      }
    }
    if (files.length > 0) {
      event.preventDefault();
      this.addFiles(files);
    }
  }

  handleDragOver(event: DragEvent): void {
    if (!this.attachmentsEnabled()) {
      return;
    }
    event.preventDefault();
    if (event.dataTransfer) {
      event.dataTransfer.dropEffect = 'copy';
    }
  }

  handleDragEnter(event: DragEvent): void {
    if (!this.attachmentsEnabled()) {
      return;
    }
    event.preventDefault();
    this.dragCounter.update((n) => n + 1);
  }

  handleDragLeave(event: DragEvent): void {
    if (!this.attachmentsEnabled()) {
      return;
    }
    event.preventDefault();
    this.dragCounter.update((n) => Math.max(0, n - 1));
  }

  handleDrop(event: DragEvent): void {
    if (!this.attachmentsEnabled()) {
      return;
    }
    event.preventDefault();
    this.dragCounter.set(0);
    const files = event.dataTransfer?.files;
    if (files && files.length > 0) {
      this.addFiles(Array.from(files));
    }
  }

  submit(): void {
    if (this.disabled()) {
      return;
    }

    const currentState = this.state();

    if (currentState === 'streaming') {
      this.canceled.emit();
      return;
    }

    if (currentState === 'error') {
      this.retried.emit();
      return;
    }

    const event: PromptInputSubmitEvent = {
      value: this.value(),
      attachments: this.attachments(),
      preventDefault: () => {
        /* Consumer can short-circuit clearing/UI by calling this. */
      },
    };
    this.submitted.emit(event);
  }

  clear(): void {
    this.value.set('');
    this.attachments.set([]);
  }

  focusTextarea(): void {
    const textarea = this.elementRef.nativeElement.querySelector('textarea');
    textarea?.focus();
  }

  addFiles(files: readonly File[]): void {
    for (const file of files) {
      const error = this.validateFile(file);
      if (error) {
        this.attachmentError.emit(error);
        continue;
      }
      this.attachments.update((prev) => [...prev, toAttachmentData(file)]);
    }
  }

  /**
   * Remove an attachment by reference, by id, or by underlying File. The
   * three signatures let consumers match whatever they have in hand
   * (full object, just the id, or the original File from drag-drop).
   */
  removeAttachment(target: AttachmentData | string | File): void {
    this.attachments.update((prev) =>
      prev.filter((item) => {
        if (typeof target === 'string') return item.id !== target;
        if (target instanceof File) return item.file !== target;
        return item.id !== target.id;
      }),
    );
  }

  private validateFile(file: File): PromptInputAttachmentError | null {
    const accept = this.acceptAttachments();
    if (accept !== false && accept.length > 0) {
      const isAccepted = accept.some((pattern) => {
        if (pattern.endsWith('/*')) {
          return file.type.startsWith(pattern.slice(0, -1));
        }
        return file.type === pattern;
      });
      if (!isAccepted) {
        return {
          file,
          reason: 'invalid-mime',
          message: `MIME type "${file.type}" not accepted`,
        };
      }
    }

    if (file.size > this.maxAttachmentSize()) {
      const mb = (this.maxAttachmentSize() / (1024 * 1024)).toFixed(1);
      return {
        file,
        reason: 'too-large',
        message: `File "${file.name}" exceeds maximum size of ${mb} MB`,
      };
    }

    if (this.attachments().length >= this.maxAttachments()) {
      return {
        file,
        reason: 'max-count',
        message: `Maximum of ${this.maxAttachments()} attachments reached`,
      };
    }

    return null;
  }

  private handleEscape(): void {
    const currentState = this.state();
    if (currentState === 'streaming') {
      this.canceled.emit();
      return;
    }
    this.clear();
  }
}

import {
  AfterViewInit,
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  HostListener,
  inject,
  input,
  OnDestroy,
  ViewChild,
  ViewEncapsulation,
} from '@angular/core';

import { cn } from '@gremorie/ng-core';

import { PromptInput } from './prompt-input';

@Component({
  selector: 'prompt-input-textarea',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <textarea
      #textarea
      [class]="textareaClass()"
      [value]="parent.value()"
      [disabled]="isDisabled()"
      [attr.aria-disabled]="isDisabled() ? 'true' : null"
      [attr.aria-label]="ariaLabel()"
      [placeholder]="placeholder()"
      [rows]="rows()"
      [attr.maxlength]="maxLength() ?? null"
      [attr.data-state]="parent.state()"
      aria-multiline="true"
      (input)="handleInput($event)"
    ></textarea>
  `,
})
export class PromptInputTextarea implements AfterViewInit, OnDestroy {
  protected readonly parent = inject(PromptInput);

  @ViewChild('textarea', { static: true })
  private readonly textareaRef!: ElementRef<HTMLTextAreaElement>;

  readonly placeholder = input<string>('Ask anything…');
  readonly rows = input<number>(1);
  readonly maxLength = input<number | null>(null);
  readonly ariaLabel = input<string>('Prompt');
  readonly maxHeightPx = input<number>(192); // 12rem default

  protected readonly isDisabled = (): boolean =>
    this.parent.disabled() || this.parent.state() === 'submitted';

  protected readonly textareaClass = () =>
    cn(
      'min-h-[2.5rem] w-full resize-none border-0 bg-transparent text-foreground',
      'placeholder:text-muted-foreground',
      'focus:outline-none focus-visible:outline-none',
      'disabled:cursor-not-allowed disabled:opacity-50',
      'overflow-y-auto',
      'field-sizing-content',
    );

  private resizeObserver?: ResizeObserver;

  ngAfterViewInit(): void {
    this.applyMaxHeight();
    this.autoExpand(); // initial fit

    // Fallback: on browsers without field-sizing, observe value changes
    if (!this.hasFieldSizingSupport()) {
      // No-op — auto-expand happens on input.
    }
  }

  ngOnDestroy(): void {
    this.resizeObserver?.disconnect();
  }

  @HostListener('window:resize')
  onResize(): void {
    this.autoExpand();
  }

  handleInput(event: Event): void {
    const target = event.target as HTMLTextAreaElement;
    this.parent.value.set(target.value);
    if (!this.hasFieldSizingSupport()) {
      this.autoExpand();
    }
  }

  focus(): void {
    this.textareaRef.nativeElement.focus();
  }

  blur(): void {
    this.textareaRef.nativeElement.blur();
  }

  private applyMaxHeight(): void {
    const el = this.textareaRef.nativeElement;
    el.style.maxHeight = `${this.maxHeightPx()}px`;
  }

  private autoExpand(): void {
    const el = this.textareaRef.nativeElement;
    el.style.height = 'auto';
    const next = Math.min(el.scrollHeight, this.maxHeightPx());
    el.style.height = `${next}px`;
  }

  private hasFieldSizingSupport(): boolean {
    return (
      typeof CSS !== 'undefined' &&
      typeof CSS.supports === 'function' &&
      CSS.supports('field-sizing', 'content')
    );
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  input,
  ViewEncapsulation,
} from '@angular/core';
import { cva } from 'class-variance-authority';

import { PromptInput } from './prompt-input';
import { PromptInputState } from './prompt-input.types';

const ICON_MAP: Record<PromptInputState, string> = {
  ready: 'M5 12h14M13 5l7 7-7 7',
  submitted: '', // spinner — rendered via SVG below
  streaming: 'M6 6h12v12H6z',
  error: 'M12 9v4M12 17h.01M10.29 3.86 1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z',
};

const LABEL_MAP: Record<PromptInputState, string> = {
  ready: 'Send message',
  submitted: 'Submitting',
  streaming: 'Stop generating',
  error: 'Retry',
};

const submitVariants = cva(
  'inline-flex size-9 shrink-0 items-center justify-center rounded-md transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50',
  {
    variants: {
      state: {
        ready: 'bg-primary text-primary-foreground hover:bg-primary/90',
        submitted: 'bg-muted text-muted-foreground',
        streaming: 'bg-destructive/10 text-destructive hover:bg-destructive/20',
        error: 'bg-destructive text-destructive-foreground hover:bg-destructive/90',
      },
    },
    defaultVariants: {
      state: 'ready',
    },
  },
);

@Component({
  selector: 'prompt-input-submit',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <button
      type="button"
      [class]="buttonClass()"
      [attr.aria-label]="ariaLabel()"
      [attr.aria-busy]="isBusy() ? 'true' : null"
      [attr.data-state]="state()"
      [disabled]="isDisabled()"
      (click)="handleClick()"
    >
      @if (state() === 'submitted') {
        <svg
          class="size-4 animate-spin"
          xmlns="http://www.w3.org/2000/svg"
          fill="none"
          viewBox="0 0 24 24"
          aria-hidden="true"
        >
          <circle
            cx="12"
            cy="12"
            r="10"
            stroke="currentColor"
            stroke-width="2"
            stroke-linecap="round"
            stroke-dasharray="20 40"
          ></circle>
        </svg>
      } @else {
        <svg
          class="size-4"
          xmlns="http://www.w3.org/2000/svg"
          fill="none"
          viewBox="0 0 24 24"
          stroke="currentColor"
          stroke-width="2"
          stroke-linecap="round"
          stroke-linejoin="round"
          aria-hidden="true"
        >
          <path [attr.d]="iconPath()"></path>
        </svg>
      }
    </button>
  `,
})
export class PromptInputSubmit {
  protected readonly parent = inject(PromptInput);

  readonly disabled = input<boolean>(false);

  protected readonly state = computed<PromptInputState>(() => this.parent.state());

  protected readonly isBusy = computed(
    () => this.state() === 'submitted' || this.state() === 'streaming',
  );

  protected readonly isDisabled = computed(
    () =>
      this.disabled() ||
      this.parent.disabled() ||
      this.state() === 'submitted' ||
      (this.state() === 'ready' && this.parent.value().trim().length === 0),
  );

  protected readonly ariaLabel = computed(() => LABEL_MAP[this.state()]);
  protected readonly iconPath = computed(() => ICON_MAP[this.state()]);

  protected readonly buttonClass = computed(() =>
    submitVariants({ state: this.state() }),
  );

  handleClick(): void {
    this.parent.submit();
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  ViewEncapsulation,
} from '@angular/core';

import { cn } from '@gremorie/ng-core';

@Component({
  selector: 'prompt-input-toolbar',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    role: 'toolbar',
    '[class]': 'hostClass',
  },
})
export class PromptInputToolbar {
  protected readonly hostClass = cn(
    'flex w-full flex-wrap items-center gap-2',
    // Light separation from the textarea above without a hard border line.
    'pt-1',
  );
}

import {
  ChangeDetectionStrategy,
  Component,
  ViewEncapsulation,
} from '@angular/core';

import { cn } from '@gremorie/ng-core';

@Component({
  selector: 'prompt-input-tools',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    role: 'group',
    '[attr.aria-label]': '"Prompt actions"',
    '[class]': 'hostClass',
  },
})
export class PromptInputTools {
  // flex-1 lets Tools occupy remaining space inside the toolbar,
  // which naturally pushes the submit button to the right edge.
  // flex-wrap keeps items readable on narrow viewports.
  protected readonly hostClass = cn(
    'flex flex-1 flex-wrap items-center gap-1',
  );
}

import {
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  HostListener,
  inject,
  input,
  signal,
  ViewEncapsulation,
} from '@angular/core';
import { cva } from 'class-variance-authority';

import { PromptInput } from './prompt-input';

const triggerVariants = cva(
  'inline-flex size-9 shrink-0 items-center justify-center rounded-md bg-transparent text-foreground transition-colors hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background disabled:pointer-events-none disabled:opacity-50',
  {
    variants: {
      open: {
        true: 'bg-accent text-accent-foreground',
        false: '',
      },
    },
    defaultVariants: {
      open: false,
    },
  },
);

/**
 * v0.1 implementation — minimal dropdown.
 * v0.2+ will migrate to @spartan-ng/brain/menu for full a11y/keyboard
 * affordances (typeahead, roving tabindex, etc).
 */
@Component({
  selector: 'prompt-input-action-menu',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <button
      type="button"
      [class]="triggerClass()"
      [attr.aria-label]="ariaLabel()"
      [attr.aria-haspopup]="'menu'"
      [attr.aria-expanded]="open() ? 'true' : 'false'"
      [disabled]="isDisabled()"
      (click)="toggle()"
    >
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true" class="size-4">
        <line x1="12" y1="5" x2="12" y2="19" />
        <line x1="5" y1="12" x2="19" y2="12" />
      </svg>
    </button>

    @if (open()) {
      <div
        role="menu"
        [attr.aria-label]="ariaLabel()"
        class="absolute z-50 mt-2 min-w-[12rem] origin-top-left rounded-md border border-border bg-popover p-1 shadow-md text-popover-foreground motion-safe:animate-[gremorie-pop-in_120ms_ease-out]"
        [style.left.px]="0"
        [style.top.px]="menuTopOffset"
      >
        <ng-content />
      </div>
    }
  `,
  host: {
    class: 'relative inline-flex',
  },
})
export class PromptInputActionMenu {
  private readonly parent = inject(PromptInput, { optional: true });
  private readonly elementRef: ElementRef<HTMLElement> = inject(ElementRef);

  readonly disabled = input<boolean>(false);
  readonly ariaLabel = input<string>('More actions');

  protected readonly open = signal(false);
  protected readonly menuTopOffset = 36; // matches button size-9

  protected readonly triggerClass = () =>
    triggerVariants({ open: this.open() });

  protected isDisabled(): boolean {
    return this.disabled() || (this.parent?.disabled() ?? false);
  }

  toggle(): void {
    this.open.update((v) => !v);
  }

  close(): void {
    this.open.set(false);
  }

  @HostListener('document:click', ['$event'])
  protected onDocumentClick(event: MouseEvent): void {
    if (!this.open()) {
      return;
    }
    const target = event.target as Node | null;
    if (target && !this.elementRef.nativeElement.contains(target)) {
      this.close();
    }
  }

  @HostListener('document:keydown.escape')
  protected onEscape(): void {
    if (this.open()) {
      this.close();
    }
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  ElementRef,
  HostListener,
  inject,
  input,
  model,
  signal,
  ViewEncapsulation,
} from '@angular/core';
import { cva } from 'class-variance-authority';

import { PromptInput } from './prompt-input';
import { PromptInputModelOption } from './prompt-input.types';

const triggerVariants = cva(
  'inline-flex h-9 min-w-0 max-w-[12rem] items-center gap-2 rounded-md px-2.5 text-sm font-medium bg-transparent text-foreground motion-safe:transition-colors hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background disabled:pointer-events-none disabled:opacity-50',
  {
    variants: {
      open: {
        true: 'bg-accent text-accent-foreground',
        false: '',
      },
    },
    defaultVariants: { open: false },
  },
);

const optionVariants = cva(
  'flex w-full items-center gap-2 rounded-sm px-2 py-1.5 text-sm text-foreground transition-colors hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:bg-accent focus-visible:text-accent-foreground disabled:pointer-events-none disabled:opacity-50',
  {
    variants: {
      selected: {
        true: 'bg-accent text-accent-foreground',
        false: '',
      },
    },
    defaultVariants: { selected: false },
  },
);

/**
 * v0.1 implementation — minimal select.
 * v0.2+ will migrate to @spartan-ng/brain/select for full a11y/keyboard
 * (combobox ARIA pattern, typeahead, etc).
 */
@Component({
  selector: 'prompt-input-model-select',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <button
      type="button"
      [class]="triggerClass()"
      [attr.aria-label]="ariaLabel()"
      [attr.aria-haspopup]="'listbox'"
      [attr.aria-expanded]="open() ? 'true' : 'false'"
      [disabled]="isDisabled()"
      (click)="toggle()"
    >
      <span class="truncate">{{ selectedLabel() }}</span>
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true" class="size-3.5 shrink-0 opacity-60">
        <polyline points="6 9 12 15 18 9" />
      </svg>
    </button>

